filehandle file = fs ::打开（＆＃34;数据/ readme.txt＆＃34;）; //检查类型if（file.isfile（））std :: cout＆lt;＆lt; ＆＃34;文件＆＃34; ＆lt;＆lt; std :: endl;否则if（file.isdirectory（））std :: cout＆lt;＆lt; ＆＃34;目录＆＃34; ＆lt;＆lt; std :: endl;否则if（file.issymboliclink（））std :: cout <＆lt;＆lt; ＆＃34; Symlink＆＃34; ＆lt;＆lt; std :: endl;否则if（！file.exists（））std :: cout <lt;＆lt; ＆＃34;文件不存在＆＃34; ＆lt;＆lt; std :: endl; //获取文件名和pathstd :: string path = file.path（）; std :: string filename = file.filename（）; //获取文件信息无符号int size = file.size（）; unsigned int atime = file.accesstime（）; unsigned int mtime = file.modificationtime（）; unsigned int uid = file.userid（）; unsigned int gid = file.groupid（）; unsigned long perm = file.permissions（）;
   仅在需要时检索文件信息，即，在上述功能之一的第一次调用上，然后在内存中缓存。当句柄的操作修改文件信息时，它会自动更新。然而，如果在应用程序之外修改文件或使用outcleHandle到同一文件的文件，则文件句柄无法知道更改。因此，必须手动更新：
   使用FileHandle，可以执行基本文件操作。对于二进制操作，例如复制或移动，第二文件处理器被认为是操作的目标。根据特工，目标不需要已经存在。如果针对目录而不是文件的目标点，则目标将被认为是在该目录中（例如，文件将被复制给定目录的文件）。
